/* Base news-item styles */
.news-item[data-v-27f758fc] {
  display: flex;
  gap: 16px;
  padding: 16px;
  border: 1px solid var(--color-border);
  border-radius: var(--border-radius-large);
  text-decoration: none;
  color: inherit;
  transition: all 0.2s ease;
  min-width: 0;
  overflow: hidden;
  box-sizing: border-box;
}

/* Default background (light gray) - for backwards compatibility */
.news-item--bg-default[data-v-27f758fc] {
  background: var(--color-background-hover);
}
.news-item--bg-default[data-v-27f758fc]:hover {
  border-color: var(--color-primary);
  background: var(--color-primary-element-light);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

/* Transparent background - for "None" option, inherits parent background */
.news-item--bg-transparent[data-v-27f758fc] {
  background: transparent;
}
.news-item--bg-transparent[data-v-27f758fc]:hover {
  background: var(--color-background-hover);
  border-color: var(--color-primary);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

/* White background - for "Light" container option */
.news-item--bg-white[data-v-27f758fc] {
  background: var(--color-main-background);
}
.news-item--bg-white[data-v-27f758fc]:hover {
  border-color: var(--color-primary);
  background: var(--color-primary-element-light);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
}

/* Dark/Primary background - semi-transparent white for dark containers */
.news-item--bg-dark[data-v-27f758fc] {
  background: var(--color-primary-element-light);
  border-color: var(--color-primary-element-light);
}
.news-item--bg-dark[data-v-27f758fc]:hover {
  background: var(--color-primary-element-hover);
  border-color: var(--color-primary-element-hover);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
}
.news-item--bg-dark .news-item-title[data-v-27f758fc] {
  color: var(--color-primary-element-text);
}
.news-item--bg-dark:hover .news-item-title[data-v-27f758fc] {
  color: var(--color-primary-element-text);
}
.news-item--bg-dark .news-item-date[data-v-27f758fc] {
  color: var(--color-primary-element-text);
  opacity: 0.8;
}
.news-item--bg-dark .news-item-excerpt[data-v-27f758fc] {
  color: var(--color-primary-element-text);
  opacity: 0.8;
}
.news-item--compact[data-v-27f758fc] {
  padding: 12px;
  gap: 12px;
}
.news-item--no-image[data-v-27f758fc] {
  flex-direction: column;
}
.news-item-image[data-v-27f758fc] {
  flex-shrink: 0;
  width: 120px;
  max-width: 100%;
  height: 80px;
  border-radius: var(--border-radius);
  overflow: hidden;
  background: var(--color-background-dark);
}
.news-item--compact .news-item-image[data-v-27f758fc] {
  width: 80px;
  max-width: 100%;
  height: 60px;
}
.news-item-image img[data-v-27f758fc] {
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.news-item-content[data-v-27f758fc] {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.news-item-title[data-v-27f758fc] {
  margin: 0;
  font-size: 14px;
  font-weight: 600;
  color: var(--color-main-text);
  line-height: 1.3;
  overflow: hidden;
  text-overflow: ellipsis;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
