.news-item--compact .news-item-title[data-v-27f758fc] {
  font-size: 13px;
  -webkit-line-clamp: 1;
}
.news-item:hover .news-item-title[data-v-27f758fc] {
  color: var(--color-primary);
}

/* Dark mode: keep white text on hover */
.news-item--bg-dark:hover .news-item-title[data-v-27f758fc] {
  color: var(--color-primary-element-text);
}
.news-item-date[data-v-27f758fc] {
