ze: 12px;\r\n  opacity: 0.7;\r\n}\r\n\r\n.news-debug {\r\n  margin-bottom: 12px;\r\n  padding: 8px;\r\n  background: var(--color-background-dark);\r\n  border: 1px solid var(--color-border);\r\n  border-radius: var(--border-radius);\r\n  font-size: 12px;\r\n}\r\n\r\n.news-debug summary {\r\n  cursor: pointer;\r\n  font-weight: 600;\r\n  color: var(--color-primary);\r\n}\r\n\r\n.news-debug pre {\r\n  margin: 8px 0 0 0;\r\n  padding: 8px;\r\n  background: var(--color-main-background);\r\n  border-radius: var(--border-radius);\r\n  overflow-x: auto;\r\n  font-size: 11px;\r\n  line-height: 1.4;\r\n  white-space: pre-wrap;\r\n  word-break: break-all;\r\n}\r\n\r\n.error-details {\r\n  margin-top: 8px;\r\n  padding: 8px;\r\n  background: var(--color-background-dark);\r\n  border-radius: var(--border-radius);\r\n  font-size: 11px;\r\n  color: var(--color-text-maxcontrast);\r\n  white-space: pre-wrap;\r\n  word-break: break-all;\r\n}\r\n</style>\r\n"],"sourceRoot":""}]);
